diff --git a/App/Layers/W1/Tests/ERM/ICNavigationCreditMemoTest.Codeunit.al b/App/Layers/W1/Tests/ERM/ICNavigationCreditMemoTest.Codeunit.al
new file mode 100644
index 00000000..f2051ca0
--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/ICNavigationCreditMemoTest.Codeunit.al
@@ -0,0 +1,135 @@
+codeunit 134199 "IC Navigation Credit Memo Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Intercompany] [Navigation]
+        IsInitialized := false;
+    end;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryApplicationArea: Codeunit "Library - Application Area";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure ICNavigateFromOutboxSalesCreditMemo()
+    var
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesCrMemoHeader: Record "Sales Cr.Memo Header";
+        ICOutboxTransactions: TestPage "IC Outbox Transactions";
+        PostedSalesCreditMemo: TestPage "Posted Sales Credit Memo";
+        ICPartnerCode: Code[20];
+        PostedCrMemoNo: Code[20];
+    begin
+        // [FEATURE] [Sales] [Credit Memo]
+        // [SCENARIO] Navigate to Posted Sales Credit Memo from IC Outbox Transactions using "Go to Document" action.
+        // This test reproduces the bug where clicking "Go to Document" from IC Outbox Transactions for a Credit Memo
+        // shows "Unable to navigate to the related document" error message.
+        // With the fix, the system should navigate to the Posted Sales Credit Memo.
+        Initialize();
+        LibraryApplicationArea.EnableEssentialSetup();
+        CleanupIC();
+
+        // [GIVEN] A Customer with IC Partner
+        ICPartnerCode := CreateICPartnerCode();
+        CreateCustomerWithICPartner(Customer, ICPartnerCode);
+
+        // [GIVEN] A Sales Credit Memo for the IC Customer
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::"Credit Memo", Customer."No.");
+        LibrarySales.CreateSalesLine(
+            SalesLine, SalesHeader, SalesLine.Type::Item,
+            LibraryInventory.CreateItemNo(), LibraryRandom.RandDecInRange(1, 10, 2));
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 200, 2));
+        SalesLine.Modify(true);
+
+        // [GIVEN] The Sales Credit Memo is posted, creating an IC Outbox Transaction
+        PostedCrMemoNo := LibrarySales.PostSalesDocument(SalesHeader, false, true);
+
+        // [GIVEN] Verify the Posted Sales Credit Memo exists
+        SalesCrMemoHeader.Get(PostedCrMemoNo);
+
+        // [WHEN] Navigating from IC Outbox Transactions using "Go to Document" action
+        ICOutboxTransactions.OpenEdit();
+        PostedSalesCreditMemo.Trap();
+        ICOutboxTransactions.GoToDocument.Invoke();
+
+        // [THEN] The Posted Sales Credit Memo page should open with the correct document
+        PostedSalesCreditMemo."No.".AssertEquals(PostedCrMemoNo);
+
+        // Cleanup
+        CleanupIC();
+        LibraryApplicationArea.DisableApplicationAreaSetup();
+    end;
+
+    local procedure Initialize()
+    var
+        ICSetup: Record "IC Setup";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"IC Navigation Credit Memo Test");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"IC Navigation Credit Memo Test");
+        if not ICSetup.Get() then begin
+            ICSetup.Init();
+            ICSetup.Insert();
+        end;
+        ICSetup."Auto. Send Transactions" := false;
+        ICSetup.Modify();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"IC Navigation Credit Memo Test");
+    end;
+
+    local procedure CleanupIC()
+    var
+        ICInboxTransaction: Record "IC Inbox Transaction";
+        ICOutboxTransaction: Record "IC Outbox Transaction";
+        HandledICInboxTrans: Record "Handled IC Inbox Trans.";
+        HandledICOutboxTrans: Record "Handled IC Outbox Trans.";
+        SalesHeader: Record "Sales Header";
+        SalesCrMemoHeader: Record "Sales Cr.Memo Header";
+    begin
+        ICInboxTransaction.DeleteAll();
+        ICOutboxTransaction.DeleteAll();
+        HandledICInboxTrans.DeleteAll();
+        HandledICOutboxTrans.DeleteAll();
+        SalesHeader.DeleteAll();
+        SalesCrMemoHeader.DeleteAll();
+    end;
+
+    local procedure CreateICPartnerCode(): Code[20]
+    var
+        ICPartner: Record "IC Partner";
+    begin
+        LibraryERM.CreateICPartner(ICPartner);
+        ICPartner.Validate("Receivables Account", LibraryERM.CreateGLAccountNo());
+        ICPartner.Validate("Payables Account", LibraryERM.CreateGLAccountNo());
+        ICPartner.Modify(true);
+        exit(ICPartner.Code);
+    end;
+
+    local procedure CreateCustomerWithICPartner(var Customer: Record Customer; ICPartnerCode: Code[20])
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("IC Partner Code", ICPartnerCode);
+        Customer.Modify(true);
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMPlanReqWksht.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMPlanReqWksht.Codeunit.al
