+++ b/App/Layers/W1/Tests/SCM/SCMPlanReqWksht.Codeunit.al
@@ -4523,6 +4523,129 @@
             BOMLineNoAndProdOrderBOMLineNoMustNotMatchErr);
     end;

+    [Test]
+    [Scope('OnPrem')]
+    procedure CommentsOnSameItemWithDiffPositionsAreCopiedCorrectlyToCompWhenCarryOutAction()
+    var
+        ProdItem: Record Item;
+        CompItem: Record Item;
+        UnitOfMeasure: Record "Unit of Measure";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionBOMLine2: Record "Production BOM Line";
+        Salesheader: Record "Sales Header";
+        ProductionBOMCommentLine: Record "Production BOM Comment Line";
+        ProductionBOMCommentLine2: Record "Production BOM Comment Line";
+        ProdOrderCompCmtLine: Record "Prod. Order Comp. Cmt Line";
+        ProdOrderComponent: Record "Prod. Order Component";
+        RequisitionLine: Record "Requisition Line";
+        Position1: Code[10];
+        Position2: Code[10];
+        Comment1: Text[80];
+        Comment2: Text[80];
+    begin
+        // [SCENARIO] When a Production BOM has multiple lines with the SAME item but different Position values and each line has comments,
+        // the comments should be correctly transferred to the corresponding Prod Order Component lines when using Carry Out Action via Planning Worksheet.
+        Initialize();
+
+        // [GIVEN] Create Unit of Measure Code.
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+
+        // [GIVEN] Create a Component Item.
+        CreateItemWithReorderPolicy(CompItem, UnitOfMeasure, ItemUnitOfMeasure, CompItem."Replenishment System"::Purchase, CompItem."Reordering Policy"::" ");
+
+        // [GIVEN] Create Production Item.
+        CreateItemWithReorderPolicy(ProdItem, UnitOfMeasure, ItemUnitOfMeasure, ProdItem."Replenishment System"::"Prod. Order", ProdItem."Reordering Policy"::Order);
+
+        // [GIVEN] Create Production BOM Header.
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ProdItem."Base Unit of Measure");
+
+        // [GIVEN] Create first Production BOM Line for the Component Item with Position "POS1".
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader,
+            ProductionBOMLine,
+            '',
+            ProductionBOMLine.Type::Item,
+            CompItem."No.",
+            LibraryRandom.RandIntInRange(1, 10));
+        Position1 := 'POS1';
+        ProductionBOMLine.Validate(Position, Position1);
+        ProductionBOMLine.Modify(true);
+
+        // [GIVEN] Create second Production BOM Line for the SAME Component Item with Position "POS2".
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader,
+            ProductionBOMLine2,
+            '',
+            ProductionBOMLine2.Type::Item,
+            CompItem."No.",
+            LibraryRandom.RandIntInRange(1, 10));
+        Position2 := 'POS2';
+        ProductionBOMLine2.Validate(Position, Position2);
+        ProductionBOMLine2.Modify(true);
+
+        // [GIVEN] Create Comment "Test1" for first BOM Line.
+        LibraryManufacturing.CreateProductionBOMCommentLine(ProductionBOMLine);
+        ProductionBOMCommentLine.SetRange("Production BOM No.", ProductionBOMHeader."No.");
+        ProductionBOMCommentLine.SetRange("BOM Line No.", ProductionBOMLine."Line No.");
+        ProductionBOMCommentLine.FindFirst();
+        Comment1 := 'Test1-' + LibraryUtility.GenerateGUID();
+        ProductionBOMCommentLine.Validate(Comment, Comment1);
+        ProductionBOMCommentLine.Modify(true);
+
+        // [GIVEN] Create Comment "Test2" for second BOM Line.
+        LibraryManufacturing.CreateProductionBOMCommentLine(ProductionBOMLine2);
+        ProductionBOMCommentLine2.SetRange("Production BOM No.", ProductionBOMHeader."No.");
+        ProductionBOMCommentLine2.SetRange("BOM Line No.", ProductionBOMLine2."Line No.");
+        ProductionBOMCommentLine2.FindFirst();
+        Comment2 := 'Test2-' + LibraryUtility.GenerateGUID();
+        ProductionBOMCommentLine2.Validate(Comment, Comment2);
+        ProductionBOMCommentLine2.Modify(true);
+
+        // [GIVEN] Update Production BOM Status.
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Validate Production BOM No. in Production Item.
+        ProdItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ProdItem.Modify(true);
+
+        // [GIVEN] Create Sales Order.
+        CreateSalesOrder(Salesheader, ProdItem);
+        LibrarySales.ReleaseSalesDocument(Salesheader);
+
+        // [GIVEN] Run Calculate Regenerative Plan.
+        RunCalculateRegenerativePlan(ProdItem."No.", '');
+
+        // [GIVEN] Accept Action Message on Requisition Line.
+        AcceptActionMessageOnReqLine(RequisitionLine, ProdItem."No.");
+
+        // [WHEN] Run Carry Out Action Plan.
+        CarryOutActionPlanForPlannedProdOrder(RequisitionLine);
+
+        // [THEN] Find Prod. Order Component lines for both positions.
+        ProdOrderComponent.SetRange("Item No.", CompItem."No.");
+        ProdOrderComponent.SetRange(Status, ProdOrderComponent.Status::Planned);
+        Assert.RecordCount(ProdOrderComponent, 2);
+
+        // [THEN] Verify first component with Position "POS1" has comment "Test1".
+        ProdOrderComponent.SetRange(Position, Position1);
+        ProdOrderComponent.FindFirst();
+        ProdOrderCompCmtLine.SetRange(Status, ProdOrderCompCmtLine.Status::Planned);
+        ProdOrderCompCmtLine.SetRange("Prod. Order No.", ProdOrderComponent."Prod. Order No.");
+        ProdOrderCompCmtLine.SetRange("Prod. Order Line No.", ProdOrderComponent."Prod. Order Line No.");
+        ProdOrderCompCmtLine.SetRange("Prod. Order Comp. Line No.", ProdOrderComponent."Line No.");
+        ProdOrderCompCmtLine.FindFirst();
+        Assert.AreEqual(Comment1, ProdOrderCompCmtLine.Comment, 'Comment for component with Position POS1 should be Test1');
+
+        // [THEN] Verify second component with Position "POS2" has comment "Test2".
+        ProdOrderComponent.SetRange(Position, Position2);
+        ProdOrderComponent.FindFirst();
+        ProdOrderCompCmtLine.SetRange("Prod. Order Comp. Line No.", ProdOrderComponent."Line No.");
+        ProdOrderCompCmtLine.FindFirst();
+        Assert.AreEqual(Comment2, ProdOrderCompCmtLine.Comment, 'Comment for component with Position POS2 should be Test2');
+    end;
+
     [Test]
