diff --git a/App/Layers/W1/Tests/SCM-Manufacturing/SCMProductionOrders.Codeunit.al b/App/Layers/W1/Tests/SCM-Manufacturing/SCMProductionOrders.Codeunit.al
index 0d170d89..87fe0b34 100644
--- a/App/Layers/W1/Tests/SCM-Manufacturing/SCMProductionOrders.Codeunit.al
+++ b/App/Layers/W1/Tests/SCM-Manufacturing/SCMProductionOrders.Codeunit.al
@@ -4794,6 +4794,64 @@ codeunit 137069 "SCM Production Orders"
         Assert.ExpectedError(StrSubstNo(ProductionBlockedOutputItemErr, Item.TableCaption(), Item."No.", Item.FieldCaption("Production Blocked"), Item."Production Blocked"));
     end;

+    [Test]
+    [HandlerFunctions('ProdOrderCreatedMessageHandler')]
+    [Scope('OnPrem')]
+    procedure ProdOrderComponentQtyPerNotZeroWhenItemUOMHasQtyRoundingPrecision()
+    var
+        CompItem: Record Item;
+        ProdItem: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        QtyPer: Decimal;
+    begin
+        // [FEATURE] [Production Order] [Production BOM] [Item Unit of Measure]
+        // [SCENARIO] When Component Item has UOM with "Qty. Rounding Precision" = 1 and Prod BOM "Quantity Per" is fractional,
+        // the Prod. Order Component should retain the fractional "Quantity per" instead of rounding to 0.
+        Initialize();
+
+        // [GIVEN] Component Item with Replenishment System = Purchase
+        CreateItem(CompItem, CompItem."Replenishment System"::Purchase);
+        CompItem.Validate("Rounding Precision", 0.01);
+        CompItem.Modify(true);
+
+        // [GIVEN] Component Item's Base UOM has "Qty. Rounding Precision" = 1
+        ItemUnitOfMeasure.Get(CompItem."No.", CompItem."Base Unit of Measure");
+        ItemUnitOfMeasure."Qty. Rounding Precision" := 1;
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] Production Item with Replenishment System = Prod. Order
+        CreateItem(ProdItem, ProdItem."Replenishment System"::"Prod. Order");
+        ProdItem.Validate("Rounding Precision", 1);
