+    [Test]
+    [Scope('OnPrem')]
+    procedure InvoiceDiscountPreservedWhenCurrencyFactorChangesAndNoLineDiscount()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+        CurrencyExchangeRate2: Record "Currency Exchange Rate";
+        Currency: Record Currency;
+        Item: Record Item;
+        CustomerNo: Code[20];
+        InvoiceDiscountAmount: Decimal;
+        NewExchangeRateDate: Date;
+        OldCurrencyFactor: Decimal;
+    begin
+        // [FEATURE] [FCY] [Sales] [Invoice Discount]
+        // [SCENARIO] Invoice discount is preserved when currency factor changes due to posting date change and line discount % is zero.
+
+        // [GIVEN] Create Currency with two Exchange Rates (on different dates)
+        Initialize();
+        LibraryERM.CreateCurrency(Currency);
+        LibraryERM.SetCurrencyGainLossAccounts(Currency);
+        GetCurrency(Currency, Currency.Code);
+
+        // Create first exchange rate
+        CreateExchangeRate(CurrencyExchangeRate, Currency.Code, WorkDate());
+
+        // Create second exchange rate on a later date with different rate
+        NewExchangeRateDate := CalcDate('<+14D>', WorkDate());
+        CreateExchangeRate(CurrencyExchangeRate2, Currency.Code, NewExchangeRateDate);
+
+        // [GIVEN] Create Sales Order with Currency and Item
+        CustomerNo := CreateCustomerWithCurrency('');
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, CustomerNo);
+        SalesHeader.Validate("Currency Code", Currency.Code);
+        SalesHeader.Modify(true);
+
+        // [GIVEN] Create Sales Line with Unit Price but no Line Discount
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 1000, 2));
+        Item.Modify(true);
+
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", LibraryRandom.RandInt(10));
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 1000, 2));
+        SalesLine.Validate("Line Discount %", 0);
+        SalesLine.Modify(true);
+
+        // [GIVEN] Apply Invoice Discount Amount to the Sales Line
+        InvoiceDiscountAmount := Round(SalesLine."Line Amount" * 0.1, Currency."Amount Rounding Precision");
+        SalesLine.Validate("Inv. Discount Amount", InvoiceDiscountAmount);
+        SalesLine.Modify(true);
+
+        // Verify Line Discount % is zero as expected
+        SalesLine.TestField("Line Discount %", 0);
+
+        // Store original currency factor
+        OldCurrencyFactor := SalesHeader."Currency Factor";
+
+        // [WHEN] Change Posting Date to a date with different exchange rate (triggering currency factor update)
+        SalesHeader.SetHideValidationDialog(true);
+        SalesHeader.Validate("Posting Date", NewExchangeRateDate);
+        SalesHeader.Modify(true);
+
+        // Verify currency factor actually changed
+        Assert.AreNotEqual(OldCurrencyFactor, SalesHeader."Currency Factor",
+            'Currency factor should have changed due to different exchange rate on new posting date.');
+
+        // [THEN] Invoice Discount Amount should be preserved on the Sales Line
+        SalesLine.Find();
+        Assert.AreEqual(InvoiceDiscountAmount, SalesLine."Inv. Discount Amount",
+            'Invoice Discount Amount should be preserved when currency factor changes and Line Discount % is zero.');
+    end;
 }

