+        ParentItem.Validate("Costing Method", ParentItem."Costing Method"::Standard);
+        ParentItem.Modify(true);
+
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        CalcStandardCost.CalcItem(ParentItem."No.", false);
+
+        // [WHEN] Calculate BOM tree with component having NO Production BOM
+        CalculateTree(BOMBuffer, ParentItem);
+
+        // [THEN] Find the Rolled-up Capacity Cost for the component
+        BOMBuffer.SetRange(Type, BOMBuffer.Type::Item);
+        BOMBuffer.SetRange("No.", ComponentItem."No.");
+        BOMBuffer.FindFirst();
+        RolledUpCapacityCostWithNoBOM := BOMBuffer."Rolled-up Capacity Cost";
+
+        // [GIVEN] Create an empty Production BOM and assign it to the component item
+        LibraryManufacturing.CreateProductionBOMHeader(EmptyProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.UpdateProductionBOMStatus(EmptyProductionBOMHeader, EmptyProductionBOMHeader.Status::Certified);
+
+        ComponentItem.Get(ComponentItem."No.");
+        ComponentItem.Validate("Production BOM No.", EmptyProductionBOMHeader."No.");
+        ComponentItem.Modify(true);
+
+        CalcStandardCost.CalcItem(ParentItem."No.", false);
+
+        // [WHEN] Calculate BOM tree again with component having an empty Production BOM
+        CalculateTree(BOMBufferWithEmptyBOM, ParentItem);
+
+        // [THEN] Find the Rolled-up Capacity Cost for the component with empty BOM
+        BOMBufferWithEmptyBOM.SetRange(Type, BOMBufferWithEmptyBOM.Type::Item);
+        BOMBufferWithEmptyBOM.SetRange("No.", ComponentItem."No.");
+        BOMBufferWithEmptyBOM.FindFirst();
+        RolledUpCapacityCostWithEmptyBOM := BOMBufferWithEmptyBOM."Rolled-up Capacity Cost";
+
+        // [THEN] Rolled-up Capacity Cost should be the same for both scenarios
+        // Empty BOM should behave the same as no BOM
+        Assert.AreEqual(
+            RolledUpCapacityCostWithNoBOM,
+            RolledUpCapacityCostWithEmptyBOM,
+            'Rolled-up Capacity Cost should be the same for empty BOM as for no BOM');
+    end;
 }

