index 00000000..853aa29c
--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/AccountReceivablesKPIsTest.Codeunit.al
@@ -0,0 +1,132 @@
+codeunit 134990 "Account Receivables KPIs Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Account Receivables KPIs]
+    end;
+
+    var
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure TotalOverdueLCYUsesTodayNotWorkDate()
+    var
+        FinanceCue: Record "Finance Cue";
+        DetailedCustLedgEntry: Record "Detailed Cust. Ledg. Entry";
+        AccountReceivablesKPIs: TestPage "Account Receivables KPIs";
+        TestAmount: Decimal;
+        OriginalWorkDate: Date;
+    begin
+        // [FEATURE] [Account Receivables KPIs] [Total Overdue (LCY)]
+        // [SCENARIO] The Total Overdue (LCY) cue uses Today() for the Overdue Date Filter, not WorkDate()
+        // This test verifies the fix that changed the filter from WorkDate() to Today()
+        Initialize();
+
+        // [GIVEN] Original WorkDate is saved and WorkDate is set to a date in the past (before Today)
+        OriginalWorkDate := WorkDate();
+        WorkDate(Today() - 10);
+
+        // [GIVEN] Delete existing data to have a clean state
+        DetailedCustLedgEntry.DeleteAll();
+        if FinanceCue.Get() then
+            FinanceCue.Delete();
+
+        // [GIVEN] A Detailed Customer Ledger Entry with "Initial Entry Due Date" = Today() - 5 
+        // With WorkDate = Today - 10, a due date of Today - 5:
+        //   - IS overdue based on Today() (since Today - 5 <= Today)
+        //   - Is NOT overdue based on WorkDate() (since Today - 5 > Today - 10)
+        // So if the page uses Today(), the entry IS included in Total Overdue
+        // If the page incorrectly uses WorkDate(), the entry would NOT be included
+        TestAmount := LibraryRandom.RandDecInRange(100, 1000, 2);
+        MockDetailedCustLedgEntry(Today() - 5, TestAmount);
+
+        // [WHEN] The Account Receivables KPIs page is opened
+        AccountReceivablesKPIs.OpenView();
+
+        // [THEN] The Total Overdue (LCY) on the page should include the entry (proving Today() is used)
+        AccountReceivablesKPIs."Sales - Total Overdue (LCY)".AssertEquals(TestAmount);
+
+        AccountReceivablesKPIs.Close();
+
+        // [CLEANUP] Restore original WorkDate
+        WorkDate(OriginalWorkDate);
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure TotalOverdueLCYExcludesEntriesAfterToday()
+    var
+        FinanceCue: Record "Finance Cue";
+        DetailedCustLedgEntry: Record "Detailed Cust. Ledg. Entry";
+        AccountReceivablesKPIs: TestPage "Account Receivables KPIs";
+        TestAmount: Decimal;
+        OriginalWorkDate: Date;
+    begin
+        // [FEATURE] [Account Receivables KPIs] [Total Overdue (LCY)]
+        // [SCENARIO] Entries with "Initial Entry Due Date" > Today() are not included in Total Overdue (LCY)
+        // This test verifies that the page uses Today() and excludes future entries
+        Initialize();
+
+        // [GIVEN] Original WorkDate is saved and WorkDate is set to a date in the future (after Today)
+        OriginalWorkDate := WorkDate();
+        WorkDate(Today() + 10);
+
+        // [GIVEN] Delete existing data to have a clean state
+        DetailedCustLedgEntry.DeleteAll();
+        if FinanceCue.Get() then
+            FinanceCue.Delete();
+
+        // [GIVEN] A Detailed Customer Ledger Entry with "Initial Entry Due Date" = Today() + 5
+        // With WorkDate = Today + 10, a due date of Today + 5:
+        //   - Is NOT overdue based on Today() (since Today + 5 > Today)
+        //   - WOULD be overdue based on WorkDate() (since Today + 5 <= Today + 10)
+        // So if the page uses Today(), the entry is NOT included
+        // If the page incorrectly uses WorkDate(), the entry WOULD be included
+        TestAmount := LibraryRandom.RandDecInRange(100, 1000, 2);
+        MockDetailedCustLedgEntry(Today() + 5, TestAmount);
+
+        // [WHEN] The Account Receivables KPIs page is opened
+        AccountReceivablesKPIs.OpenView();
+
+        // [THEN] The Total Overdue (LCY) on the page should NOT include the entry (proving Today() is used)
+        AccountReceivablesKPIs."Sales - Total Overdue (LCY)".AssertEquals(0);
+
+        AccountReceivablesKPIs.Close();
+
+        // [CLEANUP] Restore original WorkDate
+        WorkDate(OriginalWorkDate);
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Account Receivables KPIs Test");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Account Receivables KPIs Test");
+        IsInitialized := true;
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Account Receivables KPIs Test");
+    end;
+
+    local procedure MockDetailedCustLedgEntry(InitialEntryDueDate: Date; AmountLCY: Decimal)
+    var
+        DetailedCustLedgEntry: Record "Detailed Cust. Ledg. Entry";
+    begin
+        DetailedCustLedgEntry.Init();
+        DetailedCustLedgEntry."Entry No." := LibraryUtility.GetNewRecNo(DetailedCustLedgEntry, DetailedCustLedgEntry.FieldNo("Entry No."));
+        DetailedCustLedgEntry."Initial Entry Due Date" := InitialEntryDueDate;
+        DetailedCustLedgEntry."Amount (LCY)" := AmountLCY;
+        DetailedCustLedgEntry."Posting Date" := Today();
+        DetailedCustLedgEntry."Entry Type" := DetailedCustLedgEntry."Entry Type"::"Initial Entry";
+        DetailedCustLedgEntry."Document Type" := DetailedCustLedgEntry."Document Type"::Invoice;
+        DetailedCustLedgEntry.Insert();
+    end;
+}

