diff --git a/App/Layers/W1/Tests/SCM-Manufacturing/SCMSKULowLevelCode.Codeunit.al b/App/Layers/W1/Tests/SCM-Manufacturing/SCMSKULowLevelCode.Codeunit.al
new file mode 100644
index 00000000..63389858
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM-Manufacturing/SCMSKULowLevelCode.Codeunit.al
@@ -0,0 +1,275 @@
+// ------------------------------------------------------------------------------------------------
