+// ------------------------------------------------------------------------------------------------
+namespace Microsoft.Manufacturing.Test;
+
+using Microsoft.Manufacturing.Setup;
+using Microsoft.Inventory.Item;
+using Microsoft.Inventory.Location;
+using Microsoft.Manufacturing.ProductionBOM;
+
+codeunit 137040 "SCM SKU Low Level Code"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Manufacturing] [SKU] [Low-Level Code] [SCM]
+    end;
+
+    var
+        ManufacturingSetup: Record "Manufacturing Setup";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure SKUProductionBOMUpdatesComponentLowLevelCode()
+    var
+        TempManufacturingSetup: Record "Manufacturing Setup" temporary;
+        ComponentItem: Record Item;
+        MainItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        StockkeepingUnit: Record "Stockkeeping Unit";
+        Location: Record Location;
+    begin
+        // [SCENARIO] When setting Production BOM No. on a Stockkeeping Unit with Dynamic Low-Level Code enabled,
+        // the low-level code for the component items should be updated correctly.
+        // This ensures Calculate Regenerative Plan in planning worksheet plans components in first run.
+
+        // [GIVEN] Dynamic Low-Level Code is enabled in Manufacturing Setup
+        Initialize();
+        UpdateManufacturingSetup(TempManufacturingSetup, true);
+
+        // [GIVEN] A component item with Replenishment System = Purchase and Reorder Policy = Order
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Reordering Policy", ComponentItem."Reordering Policy"::Order);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] A main item with Replenishment System = Prod. Order
+        LibraryInventory.CreateItem(MainItem);
+        MainItem.Validate("Replenishment System", MainItem."Replenishment System"::"Prod. Order");
+        MainItem.Validate("Reordering Policy", MainItem."Reordering Policy"::"Lot-for-Lot");
+        MainItem.Modify(true);
+
+        // [GIVEN] A certified Production BOM with the component item
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, MainItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] A location for the SKU
+        LibraryWarehouse.CreateLocation(Location);
+
+        // [GIVEN] An SKU for the main item at the location
+        LibraryInventory.CreateStockkeepingUnitForLocationAndVariant(StockkeepingUnit, Location.Code, MainItem."No.", '');
+        StockkeepingUnit.Validate("Replenishment System", StockkeepingUnit."Replenishment System"::"Prod. Order");
+
+        // [WHEN] Setting the Production BOM No. on the SKU (not on the Item directly)
+        StockkeepingUnit.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        StockkeepingUnit.Modify(true);
+
+        // [THEN] The component item's low-level code should be updated to 1 or higher
+        ComponentItem.Get(ComponentItem."No.");
+        Assert.IsTrue(ComponentItem."Low-Level Code" >= 1, 'Component item should have Low-Level Code >= 1 after setting Production BOM on SKU');
+
+        // [THEN] The main item's low-level code should be 0 (it is not a component of another BOM)
+        MainItem.Get(MainItem."No.");
+        Assert.AreEqual(0, MainItem."Low-Level Code", 'Main item should have Low-Level Code = 0');
+
+        // [THEN] The Production BOM Header should have low-level code >= 1
+        ProductionBOMHeader.Get(ProductionBOMHeader."No.");
+        Assert.IsTrue(ProductionBOMHeader."Low-Level Code" >= 1, 'Production BOM should have Low-Level Code >= 1');
+
+        // Tear Down
+        RestoreManufacturingSetup(TempManufacturingSetup);
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure SKUProductionBOMWithNestedComponentsUpdatesLowLevelCodes()
+    var
+        TempManufacturingSetup: Record "Manufacturing Setup" temporary;
+        SubComponentItem: Record Item;
+        ComponentItem: Record Item;
+        MainItem: Record Item;
+        ComponentBOMHeader: Record "Production BOM Header";
+        MainBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        StockkeepingUnit: Record "Stockkeeping Unit";
+        Location: Record Location;
+    begin
+        // [SCENARIO] When setting Production BOM No. on a SKU for an item with nested components,
+        // the low-level codes should be calculated correctly for all items in the hierarchy.
+
+        // [GIVEN] Dynamic Low-Level Code is enabled in Manufacturing Setup
+        Initialize();
+        UpdateManufacturingSetup(TempManufacturingSetup, true);
+
+        // [GIVEN] A sub-component item (lowest level)
+        LibraryInventory.CreateItem(SubComponentItem);
+        SubComponentItem.Validate("Replenishment System", SubComponentItem."Replenishment System"::Purchase);
+        SubComponentItem.Validate("Reordering Policy", SubComponentItem."Reordering Policy"::Order);
+        SubComponentItem.Modify(true);
+
+        // [GIVEN] A component item that uses sub-component
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::"Prod. Order");
+        ComponentItem.Validate("Reordering Policy", ComponentItem."Reordering Policy"::Order);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] A certified Production BOM for component with sub-component
+        LibraryManufacturing.CreateProductionBOMHeader(ComponentBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ComponentBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, SubComponentItem."No.", 1);
+        ComponentBOMHeader.Validate(Status, ComponentBOMHeader.Status::Certified);
+        ComponentBOMHeader.Modify(true);
+
+        // Assign the component BOM to the component item
+        ComponentItem.Validate("Production BOM No.", ComponentBOMHeader."No.");
+        ComponentItem.Modify(true);
+
+        // [GIVEN] A main item
+        LibraryInventory.CreateItem(MainItem);
+        MainItem.Validate("Replenishment System", MainItem."Replenishment System"::"Prod. Order");
+        MainItem.Validate("Reordering Policy", MainItem."Reordering Policy"::"Lot-for-Lot");
+        MainItem.Modify(true);
+
+        // [GIVEN] A certified Production BOM for main item with component
+        LibraryManufacturing.CreateProductionBOMHeader(MainBOMHeader, MainItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            MainBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        MainBOMHeader.Validate(Status, MainBOMHeader.Status::Certified);
+        MainBOMHeader.Modify(true);
+
+        // [GIVEN] A location for the SKU
+        LibraryWarehouse.CreateLocation(Location);
+
+        // [GIVEN] An SKU for the main item at the location
+        LibraryInventory.CreateStockkeepingUnitForLocationAndVariant(StockkeepingUnit, Location.Code, MainItem."No.", '');
+        StockkeepingUnit.Validate("Replenishment System", StockkeepingUnit."Replenishment System"::"Prod. Order");
+
+        // [WHEN] Setting the Production BOM No. on the SKU
+        StockkeepingUnit.Validate("Production BOM No.", MainBOMHeader."No.");
+        StockkeepingUnit.Modify(true);
+
+        // [THEN] The sub-component item's low-level code should be updated (>= 2)
+        SubComponentItem.Get(SubComponentItem."No.");
+        Assert.IsTrue(SubComponentItem."Low-Level Code" >= 2, 'Sub-component item should have Low-Level Code >= 2');
+
+        // [THEN] The component item's low-level code should be >= 1
+        ComponentItem.Get(ComponentItem."No.");
+        Assert.IsTrue(ComponentItem."Low-Level Code" >= 1, 'Component item should have Low-Level Code >= 1');
+
+        // [THEN] The main item's low-level code should be 0
+        MainItem.Get(MainItem."No.");
+        Assert.AreEqual(0, MainItem."Low-Level Code", 'Main item should have Low-Level Code = 0');
+
+        // Tear Down
+        RestoreManufacturingSetup(TempManufacturingSetup);
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure SKUProductionBOMNoChangeDoesNotRecalculate()
+    var
+        TempManufacturingSetup: Record "Manufacturing Setup" temporary;
+        ComponentItem: Record Item;
+        MainItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        StockkeepingUnit: Record "Stockkeeping Unit";
+        Location: Record Location;
+        OriginalLowLevelCode: Integer;
+    begin
+        // [SCENARIO] When validating the same Production BOM No. on an SKU (no change),
+        // the low-level code calculation should not be triggered.
+
+        // [GIVEN] Dynamic Low-Level Code is enabled in Manufacturing Setup
+        Initialize();
+        UpdateManufacturingSetup(TempManufacturingSetup, true);
+
+        // [GIVEN] A component item
+        LibraryInventory.CreateItem(ComponentItem);
+
+        // [GIVEN] A main item
+        LibraryInventory.CreateItem(MainItem);
+
+        // [GIVEN] A certified Production BOM
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, MainItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] A location and SKU with Production BOM already set
+        LibraryWarehouse.CreateLocation(Location);
+        LibraryInventory.CreateStockkeepingUnitForLocationAndVariant(StockkeepingUnit, Location.Code, MainItem."No.", '');
+        StockkeepingUnit.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        StockkeepingUnit.Modify(true);
+
+        // Save original low-level code
+        ComponentItem.Get(ComponentItem."No.");
+        OriginalLowLevelCode := ComponentItem."Low-Level Code";
+
+        // Manually reset low-level code to verify it won't be recalculated
+        ComponentItem."Low-Level Code" := 0;
+        ComponentItem.Modify();
+
+        // [WHEN] Validating the same Production BOM No. (no actual change)
+        StockkeepingUnit.Get(Location.Code, MainItem."No.", '');
+        StockkeepingUnit.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        StockkeepingUnit.Modify(true);
+
+        // [THEN] The low-level code should remain unchanged (validation skipped when value is same)
+        ComponentItem.Get(ComponentItem."No.");
+        Assert.AreEqual(0, ComponentItem."Low-Level Code", 'Low-level code should not be recalculated when Production BOM No. is unchanged');
+
+        // Tear Down
+        RestoreManufacturingSetup(TempManufacturingSetup);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM SKU Low Level Code");
+        ManufacturingSetup.Get();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM SKU Low Level Code");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM SKU Low Level Code");
+    end;
+
+    local procedure UpdateManufacturingSetup(var BaseManufacturingSetup: Record "Manufacturing Setup"; DynamicLowLevelCode: Boolean)
+    begin
+        ManufacturingSetup.Get();
+        BaseManufacturingSetup := ManufacturingSetup;
+        BaseManufacturingSetup.Insert(true);
+
+        ManufacturingSetup."Dynamic Low-Level Code" := DynamicLowLevelCode;
+        ManufacturingSetup.Modify(true);
+    end;
+
+    local procedure RestoreManufacturingSetup(TempManufacturingSetup: Record "Manufacturing Setup" temporary)
+    begin
+        ManufacturingSetup.Get();
+        ManufacturingSetup."Dynamic Low-Level Code" := TempManufacturingSetup."Dynamic Low-Level Code";
+        ManufacturingSetup.Modify(true);
+    end;
+}

