+    [Test]
+    procedure CalcReservationQuantityIncludesTrackingStatusEntries()
+    var
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ReservationEntry: Record "Reservation Entry";
+        ReservationEntry2: Record "Reservation Entry";
+        ReservationEntry3: Record "Reservation Entry";
+        QtyPerUoM: Decimal;
+        TotalQtyBase: Decimal;
+        Qty1Base: Decimal;
+        Qty2Base: Decimal;
+        Qty3Base: Decimal;
+        ExpectedTotalQty: Decimal;
+        ActualTotalQty: Decimal;
+    begin
+        // [FEATURE] [Order Tracking] [Unit of Measure] [Reservation Entry]
+        // [SCENARIO] When CalcReservationQuantity is called for reservation entries with Tracking status,
+        // it should include all tracking entries in the calculation to avoid decimal rounding errors.
+        // This fixes the issue where tracking lines split into 3 entries with quantities ending in x.xxxx7
+        // would incorrectly sum to x.00001 instead of the expected whole number.
+        Initialize();
+
+        // [GIVEN] Item with a non-base unit of measure (CASE with 24 pcs per base UOM)
+        LibraryInventory.CreateItem(Item);
+        QtyPerUoM := 24;
+        LibraryInventory.CreateItemUnitOfMeasureCode(ItemUnitOfMeasure, Item."No.", QtyPerUoM);
+        Item.Validate("Sales Unit of Measure", ItemUnitOfMeasure.Code);
+        Item.Modify(true);
+
+        // [GIVEN] Sales order for the item using the non-base UOM
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", 12);
+        SalesLine.Validate("Unit of Measure Code", ItemUnitOfMeasure.Code);
+        SalesLine.Modify(true);
+
+        // [GIVEN] Three reservation entries with Tracking status simulating split tracking lines
+        // Total base quantity = 288 (12 CASES * 24 pcs), split into 3 tracking entries
+        TotalQtyBase := 288;
+        Qty1Base := 13; // First tracking line
+        Qty2Base := 137; // Second tracking line (137.5 would be ideal but we use integers for base qty)
+        Qty3Base := TotalQtyBase - Qty1Base - Qty2Base; // Third tracking line = 138
+
+        CreateTrackingReservationEntry(
+            ReservationEntry, Item."No.", SalesLine."Document No.", SalesLine."Line No.",
+            -Qty1Base, QtyPerUoM, ReservationEntry."Reservation Status"::Tracking);
+
+        CreateTrackingReservationEntry(
+            ReservationEntry2, Item."No.", SalesLine."Document No.", SalesLine."Line No.",
+            -Qty2Base, QtyPerUoM, ReservationEntry2."Reservation Status"::Tracking);
+
+        CreateTrackingReservationEntry(
+            ReservationEntry3, Item."No.", SalesLine."Document No.", SalesLine."Line No.",
+            -Qty3Base, QtyPerUoM, ReservationEntry3."Reservation Status"::Tracking);
+
+        // [WHEN] Validate Quantity (Base) on the third reservation entry to trigger CalcReservationQuantity
+        ReservationEntry3.Get(ReservationEntry3."Entry No.", ReservationEntry3.Positive);
+        ReservationEntry3.Validate("Quantity (Base)", -Qty3Base);
+
+        // [THEN] The total Quantity from all 3 entries should equal 12 (not 12.00001)
+        ExpectedTotalQty := -12;
+
+        ReservationEntry.Get(ReservationEntry."Entry No.", ReservationEntry.Positive);
+        ReservationEntry2.Get(ReservationEntry2."Entry No.", ReservationEntry2.Positive);
+
+        ActualTotalQty := ReservationEntry.Quantity + ReservationEntry2.Quantity + ReservationEntry3.Quantity;
+
+        Assert.AreEqual(ExpectedTotalQty, ActualTotalQty,
+            'Total Quantity should be correctly calculated when tracking entries are split');
+    end;
+
+    local procedure CreateTrackingReservationEntry(var ReservationEntry: Record "Reservation Entry"; ItemNo: Code[20]; SourceID: Code[20]; SourceRefNo: Integer; QtyBase: Decimal; QtyPerUoM: Decimal; ReservationStatus: Enum "Reservation Status")
+    var
+        LastEntryNo: Integer;
+    begin
+        ReservationEntry.Reset();
+        if ReservationEntry.FindLast() then
+            LastEntryNo := ReservationEntry."Entry No."
+        else
+            LastEntryNo := 0;
+
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := LastEntryNo + 1;
+        ReservationEntry."Item No." := ItemNo;
+        ReservationEntry."Source Type" := Database::"Sales Line";
+        ReservationEntry."Source Subtype" := 1; // Order
+        ReservationEntry."Source ID" := SourceID;
+        ReservationEntry."Source Ref. No." := SourceRefNo;
+        ReservationEntry."Reservation Status" := ReservationStatus;
+        ReservationEntry.Positive := QtyBase > 0;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUoM;
+        ReservationEntry."Quantity (Base)" := QtyBase;
+        ReservationEntry.Quantity := Round(QtyBase / QtyPerUoM, 0.00001);
+        ReservationEntry."Qty. to Handle (Base)" := QtyBase;
+        ReservationEntry."Qty. to Invoice (Base)" := QtyBase;
+        ReservationEntry."Creation Date" := WorkDate();
+        ReservationEntry.Insert();
+    end;
+
     local procedure Initialize()
     var
         InventorySetup: Record "Inventory Setup";

