diff --git a/App/Apps/W1/Shopify/test/Integration/Codeunit/ShpfyCopyDocumentTest.Codeunit.al b/App/Apps/W1/Shopify/test/Integration/Codeunit/ShpfyCopyDocumentTest.Codeunit.al
new file mode 100644
index 00000000..4944339b
--- /dev/null
+++ b/App/Apps/W1/Shopify/test/Integration/Codeunit/ShpfyCopyDocumentTest.Codeunit.al
@@ -0,0 +1,80 @@
+codeunit 139616 "Shpfy Copy Document Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Any: Codeunit Any;
+        LibraryAssert: Codeunit "Library Assert";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure CopyPostedInvoiceShouldClearShopifyOrderId()
+    var
+        Item: Record Item;
+        Customer: Record Customer;
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        ToSalesHeader: Record "Sales Header";
+        CopyDocumentMgt: Codeunit "Copy Document Mgt.";
+        OrderId: BigInteger;
+        OrderNo: Code[50];
+        PostedInvoiceNo: Code[20];
+    begin
+        // [SCENARIO] When copying a posted sales invoice that has Shopify Order Id,
+        // the new sales document should have the Shopify Order Id cleared
+        // [GIVEN] A posted sales invoice with Shopify Order Id and Order No.
+        Initialize();
+        OrderId := Any.IntegerInRange(10000, 99999);
+        OrderNo := CopyStr(Any.AlphanumericText(10), 1, MaxStrLen(OrderNo));
+        CreateItem(Item, Any.IntegerInRange(10000, 99999));
+        LibrarySales.CreateCustomer(Customer);
+        PostedInvoiceNo := CreateAndPostSalesInvoiceWithShopifyFields(Item, Customer, OrderId, OrderNo);
+        SalesInvoiceHeader.Get(PostedInvoiceNo);
+        LibraryAssert.AreEqual(OrderId, SalesInvoiceHeader."Shpfy Order Id", 'Posted invoice should have Shopify Order Id');
+        LibraryAssert.AreEqual(OrderNo, SalesInvoiceHeader."Shpfy Order No.", 'Posted invoice should have Shopify Order No.');
+
+        // [WHEN] Copying the posted invoice to a new sales invoice
+        LibrarySales.CreateSalesHeader(ToSalesHeader, ToSalesHeader."Document Type"::Invoice, Customer."No.");
+        CopyDocumentMgt.SetProperties(true, false, false, false, false, false, false);
+        CopyDocumentMgt.CopySalesDoc("Sales Document Type From"::"Posted Invoice", PostedInvoiceNo, ToSalesHeader);
+
+        // [THEN] The new sales header should have Shopify Order Id cleared
+        ToSalesHeader.Get(ToSalesHeader."Document Type", ToSalesHeader."No.");
+        LibraryAssert.AreEqual(0, ToSalesHeader."Shpfy Order Id", 'New sales header should have Shopify Order Id cleared');
+        LibraryAssert.AreEqual('', ToSalesHeader."Shpfy Order No.", 'New sales header should have Shopify Order No. cleared');
+        LibraryAssert.AreEqual(0, ToSalesHeader."Shpfy Refund Id", 'New sales header should have Shopify Refund Id cleared');
+    end;
+
+    local procedure Initialize()
+    begin
+        if IsInitialized then
+            exit;
+        IsInitialized := true;
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+    end;
+
+    local procedure CreateAndPostSalesInvoiceWithShopifyFields(Item: Record Item; Customer: Record Customer; OrderId: BigInteger; OrderNo: Code[50]): Code[20]
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+        SalesHeader."Shpfy Order Id" := OrderId;
+        SalesHeader."Shpfy Order No." := OrderNo;
+        SalesHeader.Modify();
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", 1);
+        exit(LibrarySales.PostSalesDocument(SalesHeader, true, true));
+    end;
+
+    local procedure CreateItem(var Item: Record Item; Amount: Decimal)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Unit Price", Amount);
+        Item.Validate("Last Direct Cost", Amount);
+        Item.Modify(true);
+    end;
+}

