+        // [GIVEN] Find bin in pick zone.
+        FindBinForPickZone(BinPick, Location.Code, true);
+
+        // [GIVEN] Two lots of Item put-away on the Location with different expiration dates.
+        // [GIVEN] LOT1 is expiring earlier (WorkDate + 5 days), LOT2 is expiring later (WorkDate + 10 days).
+        Quantity := LibraryRandom.RandInt(10);
+        LotNo[1] := LibraryUtility.GenerateGUID();
+        LotNo[2] := LibraryUtility.GenerateGUID();
+        ExpirationDate[1] := WorkDate() + 5;
+        ExpirationDate[2] := WorkDate() + 10;
+
+        // Post inventory for LOT1 (earlier expiring)
+        LibraryVariableStorage.Enqueue(LotNo[1]);
+        LibraryVariableStorage.Enqueue(Quantity);
+        UpdateAndTrackInventoryUsingWhseJournal(BinPick, Item, Quantity, '', ExpirationDate[1]);
+
+        // Post inventory for LOT2 (later expiring)
+        LibraryVariableStorage.Enqueue(LotNo[2]);
+        LibraryVariableStorage.Enqueue(Quantity);
+        UpdateAndTrackInventoryUsingWhseJournal(BinPick, Item, Quantity, '', ExpirationDate[2]);
+
+        // [GIVEN] First sales order with specific lot tracking for LOT1 (earlier expiring).
+        // Select item tracking entry for LOT1 - this creates specific reservation
+        LibraryVariableStorage.Enqueue(ItemTrackingMode::SelectEntries);
+        CreateAndReleaseSalesOrder(SalesHeader[1], '', Item."No.", Quantity, Location.Code, '', true, ReservationMode::" ");
+
+        // [GIVEN] Second sales order with quantity reserved but without specific lot tracking (non-specific reservation).
+        // Auto reserve will create non-specific reservation against available inventory
+        LibraryVariableStorage.Enqueue(ReservationMode::AutoReserve);
+        CreateAndReleaseSalesOrder(SalesHeader[2], '', Item."No.", Quantity, Location.Code, '', false, ReservationMode::AutoReserve);
+
+        // [GIVEN] Create warehouse shipment for the second sales order.
+        CreateWarehouseShipmentFromSalesHeader(SalesHeader[2]);
+
+        // [WHEN] Create and register pick for the second sales order.
+        // FEFO will suggest LOT1 (earlier expiring) but it's already reserved by the first sales order.
+        // Without the fix, this would fail with "Lot No. LOT1 is not available on inventory or it has already been reserved for another document."
+        CreatePickFromWarehouseShipment(WarehouseShipmentLine."Source Document"::"Sales Order", SalesHeader[2]."No.");
+
+        // Autofill qty to handle and register the pick
+        FindWarehouseActivityLine(
+          WarehouseActivityLine, WarehouseActivityLine."Source Document"::"Sales Order", SalesHeader[2]."No.",
+          WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.AutofillQtyToHandle(WarehouseActivityLine);
+        WarehouseActivityHeader.Get(WarehouseActivityLine."Activity Type", WarehouseActivityLine."No.");
+        LibraryWarehouse.RegisterWhseActivity(WarehouseActivityHeader);
+
+        // [THEN] Pick is registered successfully (no error).
+        // [THEN] The pick used LOT2 (because LOT1 was reserved by first sales order).
+        WarehouseActivityLine.Reset();
+        FilterWarehouseActivityLine(
+          WarehouseActivityLine, WarehouseActivityLine."Source Document"::"Sales Order", SalesHeader[2]."No.",
+          WarehouseActivityLine."Activity Type"::Pick);
+        Assert.RecordIsEmpty(WarehouseActivityLine);
+    end;
