         LibraryReportDataset.RunReportAndLoad(Report::"Standard Purchase - Order", PurchaseHeader, '');
     end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ReqWkshRecalculationWithLotTrackingDoesNotCreateWrongSurplusReservationEntry()
+    var
+        Item: Record Item;
+        ItemTrackingCode: Record "Item Tracking Code";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        PurchaseLine: Record "Purchase Line";
+        ReservationEntry: Record "Reservation Entry";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        SalesOrderQty: Decimal;
+        IncreasedQty: Decimal;
+        LotNo: Code[50];
+        SurplusCountBefore: Integer;
+    begin
+        // [SCENARIO] When recalculating an item in requisition worksheet with no planning results,
+        // surplus entries should not be incorrectly created for purchase lines with item tracking.
+        // This verifies the fix where prospect reservation entries are changed to surplus when transferred to purchase lines.
+        Initialize();
+
+        // [GIVEN] Create Item with Lot Tracking and Lot-for-Lot reordering policy
+        SalesOrderQty := 100;
+        IncreasedQty := 150;
+        LotNo := LibraryUtility.GenerateGUID();
+
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true);  // Lot-specific tracking
+        CreateItem(Item, Item."Reordering Policy"::"Lot-for-Lot", Item."Replenishment System"::Purchase);
+        Item.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        Item.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        Item.Modify(true);
+
+        // [GIVEN] Create a Sales Order with quantity 100
+        CreateSalesOrder(SalesHeader, SalesLine, Item."No.", SalesOrderQty);
+
+        // [GIVEN] Calculate Plan for Requisition Worksheet - this should create a line to purchase 100
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), WorkDate() + 30);
+
+        // [GIVEN] Modify the requisition line: change quantity to 150 and set Planning Flexibility to None
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate(Quantity, IncreasedQty);
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        RequisitionLine.Modify(true);
+
+        // [GIVEN] Add item tracking (Lot No.) to the requisition line for the increased quantity
+        LibraryItemTracking.CreateReqWkshItemTracking(ReservationEntry, RequisitionLine, '', LotNo, IncreasedQty);
+
+        // [GIVEN] Accept action message and carry out to create purchase order
+        AcceptActionMessage(Item."No.");
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+
+        // [GIVEN] Verify purchase order was created with item tracking
+        SelectPurchaseLine(PurchaseLine, Item."No.");
+        Assert.AreEqual(IncreasedQty, PurchaseLine.Quantity, 'Purchase order quantity should be the increased quantity');
+
+        // [GIVEN] Count existing surplus reservation entries for the purchase line
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type"::Order.AsInteger());
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", PurchaseLine."Line No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        SurplusCountBefore := ReservationEntry.Count();
+
+        // [WHEN] Calculate Plan for Requisition Worksheet again
+        // Since planning flexibility is None, no new lines should be created
+        RequisitionWkshName.FindFirst();
+        LibraryPlanning.CalculatePlanForReqWksh(
+            Item, RequisitionWkshName."Worksheet Template Name", RequisitionWkshName.Name, WorkDate(), WorkDate() + 30);
+
+        // [THEN] Verify no requisition line is created (Planning Flexibility = None prevents changes)
+        FilterOnRequisitionLine(RequisitionLine, Item."No.");
+        Assert.IsTrue(RequisitionLine.IsEmpty(), StrSubstNo(RequisitionLineMustNotExistTxt, Item."No."));
+
+        // [THEN] Verify no additional surplus reservation entries were incorrectly created
+        // The fix ensures that when prospect entries are transferred to purchase lines, 
+        // they are changed to surplus status, preventing duplicate surplus entries on recalculation
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type"::Order.AsInteger());
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", PurchaseLine."Line No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        Assert.AreEqual(SurplusCountBefore, ReservationEntry.Count(),
+            'Surplus reservation entry count should not increase after recalculating the plan');
+
+        // [THEN] Verify the total tracked quantity on the purchase line is still correct (not duplicated)
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type"::Order.AsInteger());
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", PurchaseLine."Line No.");
+        ReservationEntry.SetRange("Lot No.", LotNo);
+        ReservationEntry.CalcSums("Quantity (Base)");
+        Assert.AreEqual(IncreasedQty, ReservationEntry."Quantity (Base)",
+            'The total tracked quantity should equal the purchase line quantity, not be duplicated');
+    end;
 }

