+    [Test]
+    [Scope('OnPrem')]
+    procedure CustomerTotalAmountNotTripledWithGetShipmentLines()
+    var
+        Customer: Record Customer;
+        SalesLine: Record "Sales Line";
+        SalesShipmentLine: Record "Sales Shipment Line";
+        OrderDocNo: Code[20];
+        InvoiceDocNo: Code[20];
+        ShipmentNo: Code[20];
+        ShipmentLineNo: Integer;
+        ShippedNotInvoicedLCY: Decimal;
+    begin
+        // [SCENARIO] Customer Total Amount should not be tripled when a Sales Order is Shipped and a Sales Invoice uses Get Shipment Lines
+        Initialize();
+
+        // [GIVEN] A new customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] A Sales Order with Shipped Not Invoiced (LCY) = 10000
+        ShippedNotInvoicedLCY := LibraryRandom.RandDecInRange(1000, 10000, 2);
+        OrderDocNo := LibraryUtility.GenerateRandomCode(SalesLine.FieldNo("Document No."), DATABASE::"Sales Line");
+
+        SalesLine.Init();
+        SalesLine."Document Type" := SalesLine."Document Type"::Order;
+        SalesLine."Document No." := OrderDocNo;
+        SalesLine."Line No." := 10000;
+        SalesLine."Bill-to Customer No." := Customer."No.";
+        SalesLine."Shipped Not Invoiced (LCY)" := ShippedNotInvoicedLCY;
+        SalesLine."Outstanding Amount (LCY)" := 0;
+        SalesLine.Insert();
+
+        // [GIVEN] A Sales Shipment Line linked to the order
+        ShipmentNo := LibraryUtility.GenerateRandomCode(SalesShipmentLine.FieldNo("Document No."), DATABASE::"Sales Shipment Line");
+        ShipmentLineNo := 10000;
+
+        SalesShipmentLine.Init();
+        SalesShipmentLine."Document No." := ShipmentNo;
+        SalesShipmentLine."Line No." := ShipmentLineNo;
+        SalesShipmentLine."Bill-to Customer No." := Customer."No.";
+        SalesShipmentLine."Order No." := OrderDocNo;
+        SalesShipmentLine."Order Line No." := 10000;
+        SalesShipmentLine.Insert();
+
+        // [GIVEN] A Sales Invoice line created via Get Shipment Lines (has Shipment No. and Shipment Line No. populated)
+        InvoiceDocNo := LibraryUtility.GenerateRandomCode(SalesLine.FieldNo("Document No."), DATABASE::"Sales Line");
+
+        SalesLine.Init();
+        SalesLine."Document Type" := SalesLine."Document Type"::Invoice;
+        SalesLine."Document No." := InvoiceDocNo;
+        SalesLine."Line No." := 10000;
+        SalesLine."Bill-to Customer No." := Customer."No.";
+        SalesLine."Outstanding Amount (LCY)" := ShippedNotInvoicedLCY;
+        SalesLine."Shipment No." := ShipmentNo;
+        SalesLine."Shipment Line No." := ShipmentLineNo;
+        SalesLine.Insert();
+
+        // [WHEN] Calculate Customer's Total Amount
+        // [THEN] Customer's Total Amount = ShippedNotInvoicedLCY (not tripled)
+        // Before the fix, the total would be tripled because:
+        //   - "Shipped Not Invoiced (LCY)" from order = ShippedNotInvoicedLCY
+        //   - "Outstanding Invoices (LCY)" from invoice = ShippedNotInvoicedLCY
+        //   - SalesOutstandingAmountFromShipment = ShippedNotInvoicedLCY
+        // With the fix, the duplicate amounts are subtracted
+        Assert.AreEqual(ShippedNotInvoicedLCY, Customer.GetTotalAmountLCY(), 'Customer Total Amount should not be tripled');
+    end;
+
     [Test]
     [HandlerFunctions('ConfirmHandlerYes,MessageHandler')]
     [Scope('OnPrem')]

