+codeunit 134100 "ERM VAT Settlem JnlTempl Mand"
+{
+    // [FEATURE] [VAT Settlement] [Journal Template Name Mandatory]
+    // This test verifies that Calculate and Post VAT Settlement works correctly 
+    // when Journal Template Name Mandatory is enabled in G/L Setup.
+
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+
+    trigger OnRun()
+    begin
+    end;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcPostVATSettlementWithJnlTemplNameMandatory()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        VATEntry: Record "VAT Entry";
+        VATPostingSetup: Record "VAT Posting Setup";
+        CalcAndPostVATSettlement: Report "Calc. and Post VAT Settlement";
+    begin
+        // [SCENARIO] Calculate and Post VAT Settlement should not error when Journal Template Name Mandatory is enabled.
+        // [GIVEN] Journal Template Name Mandatory is enabled in G/L Setup.
+        // [GIVEN] A posted sales invoice with VAT.
+        // [WHEN] Run Calc. and Post VAT Settlement report with Post = true.
+        // [THEN] The report completes successfully without "Journal Template Name must have a value" error.
+        // [THEN] VAT Entry for the invoice is closed with a Settlement entry.
+
+        Initialize();
+
+        // [GIVEN] Enable Journal Template Name Mandatory in G/L Setup
+        LibraryERMCountryData.UpdateJournalTemplMandatory(true);
+
+        // [GIVEN] Create and post a sales invoice with VAT
+        LibraryERM.CreateVATPostingSetupWithAccounts(
+            VATPostingSetup, VATPostingSetup."VAT Calculation Type"::"Normal VAT", LibraryRandom.RandIntInRange(10, 25));
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(
+            SalesLine, SalesHeader, SalesLine.Type::"G/L Account",
+            LibraryERM.CreateGLAccountWithVATPostingSetup(VATPostingSetup, "General Posting Type"::Sale), 1);
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 500, 2));
+        SalesLine.Modify(true);
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+
+        // [WHEN] Run Calculate and Post VAT Settlement with Post = true
+        CalcAndPostVATSettlement.InitializeRequest(
+            WorkDate(), WorkDate(), WorkDate(),
+            LibraryUtility.GenerateGUID(), LibraryERM.CreateGLAccountNo(), false, true);
+        CalcAndPostVATSettlement.UseRequestPage(false);
+        CalcAndPostVATSettlement.SaveAsXml('');
+
+        // [THEN] VAT Entry for the invoice is closed
+        // [THEN] A Settlement type VAT entry is created
+        VATEntry.SetRange("Bill-to/Pay-to No.", SalesHeader."Sell-to Customer No.");
+        VATEntry.SetRange(Type, VATEntry.Type::Sale);
+        VATEntry.FindFirst();
+        Assert.AreNotEqual(0, VATEntry."Closed by Entry No.", 'VAT Entry should be closed after settlement');
+        
+        VATEntry.Get(VATEntry."Closed by Entry No.");
+        VATEntry.TestField(Type, VATEntry.Type::Settlement);
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"ERM VAT Settlem JnlTempl Mand");
+        LibrarySetupStorage.Restore();
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"ERM VAT Settlem JnlTempl Mand");
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateVATPostingSetup();
+        LibrarySetupStorage.Save(Database::"General Ledger Setup");
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"ERM VAT Settlem JnlTempl Mand");
+    end;
+}

