+        QtyPerUOM: Decimal;
+        PurchQty: Decimal;
+        ExpectedLineCount: Integer;
+    begin
+        // [FEATURE] [Put-Away] [Breakbulk Filter]
+        // [SCENARIO] When registering a warehouse put-away with breakbulk filter set to yes, all put-away lines are registered, not just the filtered ones.
+        // This reproduces the issue where setting "Breakbulk Filter" = yes caused only 2 of 4 lines to be registered.
+        Initialize();
+
+        // [GIVEN] Values for test
+        QtyPerUOM := 48;  // 48 PCS per BOX as in the repro steps
+        PurchQty := 10;   // 10 BOX as in the repro steps
+
+        // [GIVEN] Full WMS location with Allow Breakbulk = TRUE
+        LibraryWarehouse.CreateFullWMSLocation(Location, 1);
+        Location.Validate("Allow Breakbulk", true);
+        Location.Modify(true);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+
+        // [GIVEN] Item with Base Unit of Measure = "PCS" and alternate Unit of Measure = "BOX" (48 PCS)
+        // [GIVEN] Put-away Unit of Measure Code in the item is "PCS" (base UOM)
+        LibraryInventory.CreateItem(Item);
+        CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", QtyPerUOM);
+        UpdateItemUOM(Item, ItemUnitOfMeasure.Code, '', Item."Base Unit of Measure");
+
+        // [GIVEN] Released Purchase Order with Item in "BOX" UOM
+        CreateAndReleasePurchaseOrderWithUOM(PurchaseHeader, Location.Code, Item."No.", ItemUnitOfMeasure.Code, PurchQty);
+
+        // [GIVEN] Posted warehouse receipt which creates a put-away with breakbulk lines
+        CreateAndPostWarehouseReceiptFromPurchaseOrder(PurchaseHeader);
+
+        // [GIVEN] Find the put-away and count the lines (should be 4: 2 for breakbulk Take/Place and 2 for regular Take/Place)
