+
+        // Create Production BOM with qty per = 1
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, RawItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, RawItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // Create FG item with Indirect Cost % = 10 and assign production BOM
+        FGItemIndirectCostPct := 10;
+        LibraryInventory.CreateItem(FGItem);
+        FGItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FGItem.Validate("Indirect Cost %", FGItemIndirectCostPct);
+        FGItem.Validate("Replenishment System", FGItem."Replenishment System"::"Prod. Order");
+        FGItem.Modify(true);
+
+        // Create Firm Planned Production Order without source to manually add lines
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::"Firm Planned",
+            ProductionOrder."Source Type"::Item, FGItem."No.", 0);
+
+        // Add two production order lines with qty 10 each
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', 10);
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', 10);
+
+        // Refresh production order to calculate components - do not recalculate lines
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, false, true, true, false);
+
+        // Exercise: Calculate expected costs for all production order lines
+        ProdOrderLine.SetRange(Status, ProductionOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderLine.FindSet();
+        TotalQuantity := 0;
+        TotalMfgOvhdCost := 0;
+        ExpMatCost := 0;
+        ExpCapDirCost := 0;
+        ExpSubDirCost := 0;
+        ExpCapOvhdCost := 0;
+        ExpMfgOvhdCost := 0;
+
+        repeat
+            TotalQuantity += ProdOrderLine.Quantity;
+            MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+            MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+                ProdOrderLine, ShareOfTotalCapCost, ExpMatCost, ExpCapDirCost, ExpSubDirCost, ExpCapOvhdCost, ExpMfgOvhdCost);
+        until ProdOrderLine.Next() = 0;
+
+        TotalMfgOvhdCost := ExpMfgOvhdCost;
+
+        // Verify: Total quantity is 20, total material cost is 2000, mfg overhead is 10% = 200
+        Assert.AreEqual(20, TotalQuantity, 'Total quantity should be 20');
+        Assert.AreEqual(2000, ExpMatCost, 'Material cost should be 20 * 100 = 2000');
+        ExpectedMfgOvhdCost := Round(ExpMatCost * FGItemIndirectCostPct / 100);
+        Assert.AreEqual(ExpectedMfgOvhdCost, TotalMfgOvhdCost,
+            'Manufacturing overhead should be 10% of material cost regardless of number of lines');
+    end;
+
     [Test]
