+codeunit 134980 "Reminder Level Comm. Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerNo,LanguagesModalPageHandler')]
+    procedure AddTextForLanguageWhenNoAttachmentTextsExist()
+    var
+        ReminderTerms: Record "Reminder Terms";
+        ReminderLevel: Record "Reminder Level";
+        Language: Record Language;
+        ReminderAttachmentText: Record "Reminder Attachment Text";
+        ReminderLevelCommunicationPage: TestPage "Reminder Level Communication";
+    begin
+        // [SCENARIO 123456] Adding text for a new language when no attachment texts exist should not error
+        // This reproduces the bug where error "A reminder attachment text cannot be created without an ID" appeared
+
+        // [GIVEN] A Reminder Terms and Level without any attachment/email texts
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+
+        // Verify no attachment texts exist initially
+        Assert.IsTrue(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Reminder Attachment Text should be empty initially');
+        Assert.IsTrue(IsNullGuid(ReminderLevel."Reminder Email Text"), 'Reminder Email Text should be empty initially');
+
+        // [GIVEN] A valid language to select
+        Language.FindFirst();
+        LibraryVariableStorage.Enqueue(Language.Code);
+
+        // [WHEN] Open the Reminder Level Communication page (user declines to create default texts via ConfirmHandlerNo)
+        // and invoke the "Add New Language" action
+        ReminderLevelCommunicationPage.OpenEdit();
+        ReminderLevelCommunicationPage.GoToRecord(ReminderLevel);
+        ReminderLevelCommunicationPage."Add New Language".Invoke();
+
+        // [THEN] No error should occur and attachment texts should be created
+        ReminderLevel.Get(ReminderLevel."Reminder Terms Code", ReminderLevel."No.");
+        Assert.IsFalse(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Reminder Attachment Text should be created');
+        Assert.IsTrue(ReminderAttachmentText.Get(ReminderLevel."Reminder Attachment Text", Language.Code), 'Reminder Attachment Text record should exist for selected language');
+
+        ReminderLevelCommunicationPage.Close();
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerNo(Question: Text[1024]; var Reply: Boolean)
+    begin
+        // Decline to create default attachment/email texts when opening the page
+        Reply := false;
+    end;
+
+    [ModalPageHandler]
+    procedure LanguagesModalPageHandler(var Languages: TestPage Languages)
+    var
+        LanguageCode: Code[10];
+    begin
+        // Select the language code that was enqueued
+        LanguageCode := CopyStr(LibraryVariableStorage.DequeueText(), 1, 10);
+        Languages.GoToKey(LanguageCode);
+        Languages.OK().Invoke();
+    end;
+}

