+        ExpectedUnitCost: Decimal;
+        ExpectedUnitPrice: Decimal;
+        ExchangeRateAmount: Decimal;
+        VariantPrice: Decimal;
+        VariantUnitCost: Decimal;
+    begin
+        // [SCENARIO] Create an Item from a Shopify Product when Shop has a Currency Code. Prices should be converted from foreign currency to LCY.
+
+        // [GIVEN] A currency with exchange rate
+        Currency.Init();
+        Currency.Code := 'DKK';
+        if not Currency.Insert() then
+            Currency.Modify();
+
+        ExchangeRateAmount := 0.15; // 1 DKK = 0.15 LCY (e.g., USD)
+        CurrencyExchangeRate.Init();
+        CurrencyExchangeRate."Currency Code" := Currency.Code;
+        CurrencyExchangeRate."Starting Date" := WorkDate();
+        CurrencyExchangeRate."Exchange Rate Amount" := 100;
+        CurrencyExchangeRate."Relational Exch. Rate Amount" := Round(100 * ExchangeRateAmount, 0.00001);
+        CurrencyExchangeRate."Adjustment Exch. Rate Amount" := CurrencyExchangeRate."Exchange Rate Amount";
+        CurrencyExchangeRate."Relational Adjmt Exch Rate Amt" := CurrencyExchangeRate."Relational Exch. Rate Amount";
+        if not CurrencyExchangeRate.Insert() then
+            CurrencyExchangeRate.Modify();
+
+        // [GIVEN] The Shop with Currency Code set to the foreign currency
+        Shop := InitializeTest.CreateShop();
+        Shop."SKU Mapping" := "Shpfy SKU Mapping"::"Item No.";
+        Shop."Currency Code" := Currency.Code;
+        Shop.Modify();
+
+        // [GIVEN] A Shopify variant record with Price and Unit Cost in foreign currency
+        ShopifyVariant := ProductInitTest.CreateStandardProduct(Shop);
+        VariantPrice := 5000;
+        VariantUnitCost := 3000;
+        ShopifyVariant.Price := VariantPrice;
+        ShopifyVariant."Unit Cost" := VariantUnitCost;
+        ShopifyVariant.Modify();
+        ShopifyVariant.SetRecFilter();
+
+        // [WHEN] Executing the "Shpfy Create Item" codeunit with the "Shpfy Variant" Record.
+        Codeunit.Run(Codeunit::"Shpfy Create Item", ShopifyVariant);
+
+        // [THEN] The Item is created
+        LibraryAssert.IsFalse(IsNullGuid(ShopifyVariant."Item SystemId"), 'Item SystemId <> NullGuid');
+        LibraryAssert.IsTrue(Item.GetBySystemId(ShopifyVariant."Item SystemId"), 'Get Item');
+
+        // [THEN] The Item Unit Price and Unit Cost are converted from foreign currency to LCY
+        ExpectedUnitPrice := Round(CurrencyExchangeRate.ExchangeAmtFCYToLCY(WorkDate(), Currency.Code, VariantPrice, CurrencyExchangeRate.ExchangeRate(WorkDate(), Currency.Code)));
+        ExpectedUnitCost := Round(CurrencyExchangeRate.ExchangeAmtFCYToLCY(WorkDate(), Currency.Code, VariantUnitCost, CurrencyExchangeRate.ExchangeRate(WorkDate(), Currency.Code)));
+
+        LibraryAssert.AreEqual(ExpectedUnitPrice, Item."Unit Price", 'Unit Price should be converted from foreign currency to LCY');
+        LibraryAssert.AreEqual(ExpectedUnitCost, Item."Unit Cost", 'Unit Cost should be converted from foreign currency to LCY');
+
+        // [THEN] Verify the prices are NOT equal to the original Shopify variant prices (they should be converted)
+        LibraryAssert.AreNotEqual(VariantPrice, Item."Unit Price", 'Unit Price should not equal the original Shopify variant price when currency conversion is applied');
+        LibraryAssert.AreNotEqual(VariantUnitCost, Item."Unit Cost", 'Unit Cost should not equal the original Shopify variant unit cost when currency conversion is applied');
+    end;
 }

