+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    [Scope('OnPrem')]
+    procedure UndoTransferShipmentAfterRevaluationAdjustsCorrectly()
+    var
+        Item: Record Item;
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        FromLocation: Record Location;
+        ToLocation: Record Location;
+        TransitLocation: Record Location;
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        ValueEntry: Record "Value Entry";
+        OriginalUnitCost: Decimal;
+        RevaluedUnitCost: Decimal;
+        Qty: Decimal;
+    begin
+        // [FEATURE] [Transfer] [Order] [Undo Shipment] [Revaluation]
+        // [SCENARIO] When undoing a transfer shipment after revaluing the original inbound entry, 
+        // the resulting item ledger entry should reflect the revalued cost, not the original cost.
+        Initialize();
+
+        // [GIVEN] Create locations
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(FromLocation);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(ToLocation);
+        LibraryWarehouse.CreateInTransitLocation(TransitLocation);
+
+        // [GIVEN] Item with positive inventory on From-location with cost 10
+        OriginalUnitCost := 10;
+        RevaluedUnitCost := 12;
+        Qty := 1;
+        LibraryInventory.CreateItem(Item);
+        CreateAndPostItemJnlWithCostLocationVariant(
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", Qty, OriginalUnitCost, FromLocation.Code, '');
+
+        // [GIVEN] Find the inbound item ledger entry
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::"Positive Adjmt.");
+        ItemLedgerEntry.FindFirst();
+
+        // [GIVEN] Create and ship a Transfer Order
+        LibraryInventory.CreateTransferHeader(TransferHeader, FromLocation.Code, ToLocation.Code, TransitLocation.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", Qty);
+        LibraryInventory.PostTransferHeader(TransferHeader, true, false);
+
+        // [GIVEN] Revalue the original positive adjustment item ledger entry to 12
+        LibraryInventory.CreateItemJournalBatchByType(ItemJournalBatch, ItemJournalBatch."Template Type"::Revaluation);
+        LibraryInventory.MakeItemJournalLine(ItemJournalLine, ItemJournalBatch, Item, WorkDate(), ItemJournalLine."Entry Type"::"Positive Adjmt.", 0);
+        ItemJournalLine.Validate("Applies-to Entry", ItemLedgerEntry."Entry No.");
+        ItemJournalLine.Validate("Unit Cost (Revalued)", RevaluedUnitCost);
+        ItemJournalLine.Insert();
+        LibraryInventory.PostItemJournalBatch(ItemJournalBatch);
+
+        // [GIVEN] Run cost adjustment
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [WHEN] Undo the posted Transfer Shipment
+        LibraryInventory.UndoTransferShipments(TransferHeader."No.");
+
+        // [WHEN] Run cost adjustment again
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [THEN] The total cost amount across all item ledger entries for this item should be the revalued cost (12)
+        // because item is back in inventory with revalued cost
+        ValueEntry.SetRange("Item No.", Item."No.");
+        ValueEntry.CalcSums("Cost Amount (Actual)");
+        Assert.AreEqual(
+            RevaluedUnitCost * Qty, 
+            ValueEntry."Cost Amount (Actual)", 
+            'Total cost amount should equal the revalued cost after undo transfer shipment');
+    end;
+
     [Test]
     [HandlerFunctions('ConfirmHandlerYes')]
     [Scope('OnPrem')]

