+    [Test]
+    [Scope('OnPrem')]
+    procedure CarryOutActionMsgRespectsActionMessageFilterInPlanningWorksheet()
+    var
+        Item: Record Item;
+        PurchaseHeader: Record "Purchase Header";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionLine: Record "Requisition Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        CarryOutActionMsgPlan: Report "Carry Out Action Msg. - Plan.";
+        PurchaseOrderDate: Date;
+        SalesShipmentDate: Date;
+    begin
+        // [FEATURE] [Carry Out Action Message] [Planning Worksheet] [Action Message Filter]
+        // [SCENARIO 534100] When user filters Planning Worksheet by Action Message (e.g. Cancel) and runs
+        // Carry Out Action Message, only the filtered lines should be processed, not all lines.
+        Initialize();
+
+        // [GIVEN] Create an Item with Order reordering policy and Purchase replenishment system
+        CreateItem(Item, Item."Reordering Policy"::Order, Item."Replenishment System"::Purchase);
+
+        // [GIVEN] Create a Purchase Order for the Item dated earlier than a Sales Order shipment date
+        PurchaseOrderDate := CalcDate('<-1M>', WorkDate());
+        SalesShipmentDate := CalcDate('<+1M>', WorkDate());
+        CreatePurchaseOrder(PurchaseHeader, Item."No.", PurchaseOrderDate, LibraryRandom.RandInt(10));
+
+        // [GIVEN] Create a Sales Order for the Item with a shipment date in the future
+        CreateSalesOrder(SalesHeader, SalesLine, Item."No.", LibraryRandom.RandInt(10));
+        UpdateShipmentDateOnSalesLine(SalesLine, SalesShipmentDate);
+
+        // [GIVEN] Calculate Regenerative Plan in Planning Worksheet, which creates 2 lines:
+        // - Cancel line for the existing Purchase Order (supply not needed at old date)
+        // - New line to create a new Purchase Order for the Sales Order demand
+        LibraryPlanning.SelectRequisitionWkshName(RequisitionWkshName, RequisitionWkshName."Template Type"::Planning);
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item, PurchaseOrderDate, SalesShipmentDate);
+
+        // [GIVEN] Verify both Cancel and New action messages exist
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'Cancel action message line should exist.');
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'New action message line should exist.');
+
+        // [GIVEN] Accept only the Cancel line
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        RequisitionLine.FindFirst();
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+
+        // [WHEN] Run Carry Out Action Message with filter set to Action Message = Cancel
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        RequisitionLine.FindFirst();
+
+        Commit();
+        CarryOutActionMsgPlan.InitializeRequest(0, 1, 0, 0);
+        CarryOutActionMsgPlan.SetReqWkshLine(RequisitionLine);
+        CarryOutActionMsgPlan.SetTableView(RequisitionLine);
+        CarryOutActionMsgPlan.UseRequestPage(false);
+        CarryOutActionMsgPlan.RunModal();
+
+        // [THEN] The Cancel line should be processed (deleted from planning worksheet)
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        Assert.IsTrue(RequisitionLine.IsEmpty(), 'Cancel line should have been processed and removed.');
+
+        // [THEN] The New line should still exist (not processed because it was filtered out)
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        Assert.IsFalse(RequisitionLine.IsEmpty(), 'New line should still exist because it was filtered out.');
+
+        // [THEN] The original Purchase Order should be deleted (Cancel action was carried out)
+        PurchaseHeader.SetRange("No.", PurchaseHeader."No.");
+        Assert.IsTrue(PurchaseHeader.IsEmpty(), 'Original Purchase Order should have been cancelled.');
+    end;
+
     local procedure Initialize()
     var
         AllProfile: Record "All Profile";

