+    begin
+        // [FEATURE] [Non-Deductible VAT] [Prices Including VAT] [Rounding]
+        // [SCENARIO] Posting purchase invoice with 100% Non-Deductible VAT and vendor "Prices Including VAT" = true should not cause consistency error due to rounding issues
+        // The VAT Entry should have Base = 0 and Amount = 0 when Non-Deductible VAT % is 100
+        Initialize();
+
+        // [GIVEN] Create Normal VAT Posting Setup with VAT % = 20 and Non-Deductible VAT % = 100
