+        // [SCENARIO] Suggest Shopify payments should only match transactions with Success status
+        // [GIVEN] Multiple invoices are posted
+        Initialize();
+        Amount := Any.IntegerInRange(10000, 99999);
+        OrderIdSuccess := Any.IntegerInRange(10000, 99999);
+        OrderIdPending := Any.IntegerInRange(10000, 99999);
+        OrderIdFailure := Any.IntegerInRange(10000, 99999);
+        CreateItem(Item, Amount);
+        LibrarySales.CreateCustomer(Customer);
+        CreateAndPostSalesInvoice(Item, Customer, 1, OrderIdSuccess);
+        CreateAndPostSalesInvoice(Item, Customer, 1, OrderIdPending);
+        CreateAndPostSalesInvoice(Item, Customer, 1, OrderIdFailure);
+
+        // [GIVEN] Shopify transactions are imported with different statuses (Success, Pending, Failure)
+        CreateOrderTransactionWithStatus(OrderIdSuccess, Amount, 'manual', OrderTransaction.Type::Sale, TransactionStatus::Success);
+        CreateOrderTransactionWithStatus(OrderIdPending, Amount, 'manual', OrderTransaction.Type::Sale, TransactionStatus::Pending);
+        CreateOrderTransactionWithStatus(OrderIdFailure, Amount, 'manual', OrderTransaction.Type::Sale, TransactionStatus::Failure);
+        Commit();
+
+        // [WHEN] Suggest Shopify payments report is run
+        CashReceiptJournal.OpenView();
+        CashReceiptJournal.SuggestShopifyPayments.Invoke();
+
+        // [THEN] Only the Success transaction creates a journal line, Pending and Failure are excluded
+        GenJournalLine.SetRange("Document Type", GenJournalLine."Document Type"::Payment);
+        GenJournalLine.SetRange("Account No.", Customer."No.");
+        LibraryAssert.RecordCount(GenJournalLine, 1);
+    end;
+
+    local procedure CreateOrderTransactionWithStatus(OrderId: BigInteger; Amount: Decimal; Gateway: Code[20]; TransactionType: Enum "Shpfy Transaction Type"; TransactionStatus: Enum "Shpfy Transaction Status")
+    var
+        OrderTransaction: Record "Shpfy Order Transaction";
+    begin
+        OrderTransaction."Shopify Transaction Id" := Any.IntegerInRange(10000, 99999);
+        OrderTransaction."Shopify Order Id" := OrderId;
+        OrderTransaction.Amount := Amount;
+        OrderTransaction.Gateway := Gateway;
+        OrderTransaction.Type := TransactionType;
+        OrderTransaction.Status := TransactionStatus;
+        OrderTransaction.Insert();
+    end;
+
