+    [Test]
+    [HandlerFunctions('PurchaseStatisticsChangeVATAmountModalPageHandler')]
+    procedure PostPurchInvWithFCYNonDedVAT100PctAndVATDiff()
+    var
+        Currency: Record Currency;
+        VATPostingSetup: Record "VAT Posting Setup";
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        PurchasesPayablesSetup: Record "Purchases & Payables Setup";
+        GeneralLedgerSetup: Record "General Ledger Setup";
+        PurchaseInvoicePage: TestPage "Purchase Invoice";
+        MaxVATDifference: Decimal;
+        VATAmount: Decimal;
+        NonDeductibleVATAmount: Decimal;
+        PostedDocNo: Code[20];
+    begin
+        // [FEATURE] [UI] [FCY]
+        // [SCENARIO 562849] Stan can post purchase invoice with FCY, 100% Non-Deductible VAT and modified VAT Amount in Statistics
+
+        Initialize();
+        MaxVATDifference := LibraryRandom.RandDecInDecimalRange(0.1, 1, 2);
+        // [GIVEN] "Allow VAT Difference" is enabled in Purchases Setup
+        PurchasesPayablesSetup.Get();
+        PurchasesPayablesSetup.Validate("Allow VAT Difference", true);
+        PurchasesPayablesSetup.Modify(true);
+        // [GIVEN] "Max VAT Difference" is set in General Ledger Setup
+        GeneralLedgerSetup.Get();
+        GeneralLedgerSetup.Validate("Max. VAT Difference Allowed", MaxVATDifference);
+        GeneralLedgerSetup.Modify(true);
+        // [GIVEN] Currency EUR with "Max. VAT Difference Allowed" set
+        Currency.Get(LibraryERM.CreateCurrencyWithExchangeRate(WorkDate(), 10, 10));
+        Currency.Validate("Max. VAT Difference Allowed", MaxVATDifference);
+        Currency.Modify(true);
+        // [GIVEN] Normal VAT Posting Setup with "VAT %" = 20 and "Non-Deductible VAT %" = 100
+        LibraryERM.CreateVATPostingSetupWithAccounts(VATPostingSetup, VATPostingSetup."VAT Calculation Type"::"Normal VAT", LibraryRandom.RandIntInRange(10, 25));
+        LibraryNonDeductibleVAT.SetAllowNonDeductibleVATForVATPostingSetup(VATPostingSetup);
+        VATPostingSetup.Validate("Non-Deductible VAT %", 100);
+        VATPostingSetup.Modify(true);
+        // [GIVEN] Purchase invoice with Currency EUR
+        LibraryPurchase.CreatePurchHeader(
+            PurchaseHeader, PurchaseHeader."Document Type"::Invoice,
+            LibraryPurchase.CreateVendorWithVATBusPostingGroup(VATPostingSetup."VAT Bus. Posting Group"));
+        PurchaseHeader.Validate("Currency Code", Currency.Code);
+        PurchaseHeader.Modify(true);
+        LibraryPurchase.CreatePurchaseLine(
+            PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item,
+            LibraryInventory.CreateItemWithVATProdPostingGroup(VATPostingSetup."VAT Prod. Posting Group"), LibraryRandom.RandInt(100));
+        PurchaseLine.Validate("Direct Unit Cost", LibraryRandom.RandDec(100, 2));
+        PurchaseLine.Modify(true);
+        // [GIVEN] VAT Amount is calculated. Non-Deductible VAT Amount equals VAT Amount because 100% Non-Deductible
+        VATAmount := PurchaseLine."Amount Including VAT" - PurchaseLine.Amount - MaxVATDifference;
+        NonDeductibleVATAmount := VATAmount;
+        LibraryVariableStorage.Enqueue(NonDeductibleVATAmount);
+        LibraryVariableStorage.Enqueue(VATAmount);
+        // [GIVEN] Open purchase invoice page and change VAT Amount in Statistics
+        PurchaseInvoicePage.OpenEdit();
+        PurchaseInvoicePage.Filter.SetFilter("No.", PurchaseHeader."No.");
+        PurchaseInvoicePage.Statistics.Invoke();
+        // [GIVEN] VAT Amount is changed to create VAT Difference
+        // Called in PurchaseStatisticsChangeVATAmountModalPageHandler
+        PurchaseLine.Find();
+        PurchaseLine.TestField("VAT Difference", -MaxVATDifference);
+        // [WHEN] Post purchase invoice
+        PostedDocNo := LibraryPurchase.PostPurchaseDocument(PurchaseHeader, true, true);
+        // [THEN] Invoice is posted successfully without G/L inconsistency error
+        // [THEN] Posted invoice number is returned (not empty)
+        Assert.AreNotEqual('', PostedDocNo, 'Invoice should be posted successfully');
+        LibraryVariableStorage.AssertEmpty();
+    end;
